{
    "level": "B2–C1",
    "intro": "In this topic, you will learn <strong>passive infinitive</strong> in detail: how to form simple (to be done) and perfect (to have been done) passive infinitive, when to use them and with which verbs they are combined.",
    "rules": [
        {
            "label": "Simple",
            "color": "emerald",
            "text": "<strong>to be + V3 (Past Participle)</strong> — present/future action:",
            "example": "The report needs to be finished."
        },
        {
            "label": "Perfect",
            "color": "blue",
            "text": "<strong>to have been + V3</strong> — previous action:",
            "example": "He seems to have been promoted."
        },
        {
            "label": "Comparison",
            "color": "rose",
            "text": "Active: <strong>to do / to have done</strong> → Passive: <strong>to be done / to have been done</strong>",
            "example": "to write → to be written → to have been written"
        }
    ]
}

{
    "title": "1. Formation of the passive infinitive",
    "intro": "Comparison of active and passive forms of the infinitive:",
    "items": [
        {
            "label": "Active Simple",
            "title": "to do / to write",
            "subtitle": "I want to write a letter. - I want to write a letter."
        },
        {
            "label": "Passive Simple",
            "title": "to be done / to be written",
            "subtitle": "The letter needs to be written. - Letters need to be written."
        },
        {
            "label": "Active Perfect",
            "title": "to have done / to have written",
            "subtitle": "He claims to have written the book. - He claims to have written a book."
        },
        {
            "label": "Passive Perfect",
            "title": "to have been done / to have been written",
            "subtitle": "The book seems to have been written long ago. - The book seems to have been written a long time ago."
        }
    ]
}

{
    "title": "2. Simple passive infinitive (to be done)",
    "sections": [
        {
            "label": "After need / want / expect",
            "color": "emerald",
            "description": "When someone wants/expects <strong>something to be done</strong>:",
            "examples": [
                {
                    "en": "The report needs to be finished by Friday.",
                    "ua": "The report needs to be finished by Friday."
                },
                {
                    "en": "I want this issue to be resolved immediately.",
                    "ua": "I want this issue to be resolved immediately."
                },
                {
                    "en": "They expect the project to be approved.",
                    "ua": "They expect the project to be approved."
                },
                {
                    "en": "The car needs to be repaired.",
                    "ua": "The car needs to be repaired."
                }
            ]
        },
        {
            "label": "After seem / appear",
            "color": "blue",
            "description": "To express an <strong>impression or guess</strong>:",
            "examples": [
                {
                    "en": "The door seems to be locked.",
                    "ua": "The door seems to be locked."
                },
                {
                    "en": "He appears to be respected by everyone.",
                    "ua": "He appears to be respected by everyone."
                },
                {
                    "en": "The problem appears to be solved.",
                    "ua": "The problem appears to be solved."
                }
            ]
        },
        {
            "label": "After would like / prefer",
            "color": "amber",
            "description": "To express a <strong>desire or preference</strong>:",
            "examples": [
                {
                    "en": "I would like to be informed about the decision.",
                    "ua": "I would like to be informed about the decision."
                },
                {
                    "en": "She prefers to be left alone.",
                    "ua": "She prefers to be left alone."
                },
                {
                    "en": "We would like to be invited to the meeting.",
                    "ua": "We would like to be invited to the meeting."
                }
            ]
        }
    ]
}

{
    "title": "3. Perfect passive infinitive (to have been done)",
    "sections": [
        {
            "label": "Previous action",
            "color": "emerald",
            "description": "Indicates an action that <strong>happened before</strong> the main verb:",
            "examples": [
                {
                    "en": "He seems to have been promoted last month.",
                    "ua": "He seems to have been promoted last month."
                },
                {
                    "en": "The documents appear to have been lost.",
                    "ua": "The documents appear to have been lost."
                },
                {
                    "en": "The letter seems to have been sent already.",
                    "ua": "The letter seems to have been sent already."
                }
            ]
        },
        {
            "label": "Reporting structures",
            "color": "blue",
            "description": "In impersonal constructions with <strong>is said / believed / reported / known</strong>:",
            "examples": [
                {
                    "en": "He is believed to have been kidnapped.",
                    "ua": "He is believed to have been kidnapped."
                },
                {
                    "en": "She is reported to have been seen in Paris.",
                    "ua": "She is reported to have been seen in Paris."
                },
                {
                    "en": "The painting is thought to have been stolen.",
                    "ua": "The painting is thought to have been stolen."
                },
                {
                    "en": "He is known to have been educated in Oxford.",
                    "ua": "He is known to have been educated in Oxford."
                }
            ]
        },
        {
            "label": "After modals + have",
            "color": "rose",
            "description": "For <strong>assumptions about the past</strong>:",
            "examples": [
                {
                    "en": "The work should have been completed yesterday.",
                    "ua": "The work should have been completed yesterday."
                },
                {
                    "en": "The message must have been deleted.",
                    "ua": "The message must have been deleted."
                },
                {
                    "en": "The car could have been stolen.",
                    "ua": "The car could have been stolen."
                }
            ]
        }
    ]
}

{
    "title": "4. Verbs combined with the passive infinitive",
    "sections": [
        {
            "label": "Expectation / desire",
            "color": "emerald",
            "description": "<strong>want, need, expect, would like, prefer, wish</strong>:",
            "examples": [
                {
                    "en": "I expect to be paid on time.",
                    "ua": "I expect to be paid on time."
                },
                {
                    "en": "Nobody wants to be forgotten.",
                    "ua": "Nobody wants to be forgotten."
                },
                {
                    "en": "The floor needs to be cleaned.",
                    "ua": "The floor needs to be cleaned."
                }
            ]
        },
        {
            "label": "It seems / looks",
            "color": "blue",
            "description": "<strong>seem, appear, happen, turn out, prove</strong>:",
            "examples": [
                {
                    "en": "He seems to be trusted by his colleagues.",
                    "ua": "He seems to be trusted by his colleagues."
                },
                {
                    "en": "The theory turned out to be proven wrong.",
                    "ua": "The theory turned out to be proven wrong."
                },
                {
                    "en": "She happened to be chosen for the role.",
                    "ua": "She happened to be chosen for the role."
                }
            ]
        },
        {
            "label": "Impersonal constructions",
            "color": "amber",
            "description": "<strong>is said, is believed, is reported, is known, is thought</strong>:",
            "examples": [
                {
                    "en": "He is said to be very intelligent.",
                    "ua": "He is said to be very intelligent."
                },
                {
                    "en": "They are believed to be innocent.",
                    "ua": "They are believed to be innocent."
                },
                {
                    "en": "The company is reported to be expanding.",
                    "ua": "The company is reported to be expanding."
                }
            ]
        }
    ]
}

{
    "title": "5. Comparison: to be done vs to have been done",
    "intro": "When to use the simple or perfect passive infinitive:",
    "rows": [
        {
            "en": "to be done",
            "ua": "to be done",
            "note": "He seems to be respected. - He seems to be respected (now)."
        },
        {
            "en": "to have been done",
            "ua": "to have been done",
            "note": "He seems to have been promoted. - He seems to have been promoted (earlier)."
        },
        {
            "en": "to be done (need)",
            "ua": "to be done (need)",
            "note": "The work needs to be finished. - The work must be finished."
        },
        {
            "en": "to have been done (should)",
            "ua": "to have been done (should)",
            "note": "The work should have been finished. - The work should have been finished."
        }
    ],
    "warning": "📌 The perfect infinitive indicates an action that happened BEFORE the main verb!"
}

{
    "title": "6. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Skip to be in the passive infinitive.",
            "wrong": "The report needs finished.",
            "right": "✅ The report needs to be finished."
        },
        {
            "label": "Error 2",
            "color": "amber",
            "title": "Using V1 instead of V3.",
            "wrong": "She wants to be invite.",
            "right": "✅ She wants to be invited."
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Confusion of simple and perfect.",
            "wrong": "He seems to be promoted last year.",
            "right": "✅ He seems to have been promoted last year."
        },
        {
            "label": "Error 4",
            "color": "rose",
            "title": "Incorrect word order in the perfect tense.",
            "wrong": "to been have done",
            "right": "✅ to have been done"
        }
    ]
}
